import { useState, useEffect } from 'react';
import AuraLogo from '@/components/AuraLogo';
import { getApiBase } from '@/utils/platform';
import usePageTitle from '../hooks/usePageTitle';
import { SkeletonCardGrid } from '../components/SkeletonUI';
import s from './AISubscriptionPage.module.css';

function authHeaders() {
  const token = localStorage.getItem('aura_token');
  return token ? { Authorization: `Bearer ${token}` } : {};
}

function formatTokens(n) {
  if (n >= 1_000_000) return `${(n / 1_000_000).toFixed(0)}M`;
  if (n >= 1_000) return `${Math.round(n / 1_000)}K`;
  return String(n);
}

function TierCard({ tier, isActive, onSelect }) {
  const isPro = tier.key === 'pro';

  const cardClass = isActive
    ? s.tierCardHighlight
    : isPro
      ? s.tierCardPro
      : s.tierCard;

  return (
    <div className={cardClass}>
      {isPro && !isActive && (
        <div className={s.badgePopular}>POPULAR</div>
      )}
      {isActive && (
        <div className={s.badgeCurrent}>CURRENT</div>
      )}
      <div className={s.tierName}>{tier.label}</div>
      <div className={s.tierPriceWrap}>
        <span className={s.tierPrice}>${tier.price}</span>
        {tier.price > 0 && <span className={s.tierPeriod}>/mo</span>}
        {tier.price === 0 && <span className={s.tierPeriod}> (14 days)</span>}
      </div>
      <div className={s.featureList}>
        <div className={s.featureRow}>
          <span className={s.featurePlus}>+</span>
          {formatTokens(tier.monthly_token_limit)} tokens/mo
        </div>
        <div className={s.featureRow}>
          <span className={s.featurePlus}>+</span>
          {tier.models.join(' + ')}
        </div>
        <div>
          {tier.deep_analysis ? (
            <><span className={s.featurePlus}>+</span>Deep analysis</>
          ) : (
            <span className={s.featureDisabled}>- No deep analysis</span>
          )}
        </div>
      </div>
      {!isActive && tier.key !== 'trial' && (
        <button
          onClick={() => onSelect(tier.key)}
          className={isPro ? s.selectBtnPro : s.selectBtnDefault}
        >
          {isPro ? 'Upgrade to Pro' : `Choose ${tier.label}`}
        </button>
      )}
    </div>
  );
}

export default function AISubscriptionPage() {
  usePageTitle('AI Subscription');
  const [tiers, setTiers] = useState([]);
  const [subscription, setSubscription] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    Promise.all([
      fetch(`${getApiBase()}/subscriptions/tiers`).then((r) => r.json()),
      fetch(`${getApiBase()}/subscriptions/`, { headers: authHeaders() }).then((r) => r.json()),
    ]).then(([tiersData, subData]) => {
      setTiers(tiersData.tiers || []);
      setSubscription(subData.subscription);
      setLoading(false);
    }).catch(() => setLoading(false));
  }, []);

  const handleCheckout = async (tier) => {
    try {
      const res = await fetch(`${getApiBase()}/subscriptions/checkout`, {
        method: 'POST',
        headers: { ...authHeaders(), 'Content-Type': 'application/json' },
        body: JSON.stringify({ tier }),
      });
      const data = await res.json();
      if (data.checkout_url) {
        window.location.href = data.checkout_url;
      } else {
        alert(data.detail || data.error || 'Could not start checkout');
      }
    } catch (err) {
      alert('Checkout failed: ' + err.message);
    }
  };

  const handlePortal = async () => {
    try {
      const res = await fetch(`${getApiBase()}/subscriptions/portal`, {
        method: 'POST', headers: authHeaders(),
      });
      const data = await res.json();
      if (data.portal_url) {
        window.location.href = data.portal_url;
      } else {
        alert(data.detail || data.error || 'Could not open portal');
      }
    } catch (err) {
      alert('Portal failed: ' + err.message);
    }
  };

  if (loading) {
    return (
      <div className={s.loadingWrap}>
        <SkeletonCardGrid count={3} columns="repeat(auto-fill, minmax(220px, 1fr))" />
      </div>
    );
  }

  const activeTier = subscription?.tier || null;

  return (
    <div className={s.page}>
      <div className={s.header}>
        <AuraLogo variant="icon" height={48} glow />
        <h1 className={s.title}>AI Assistant Subscription</h1>
      </div>
      <p className={s.subtitle}>
        Choose a plan for your AI-powered trading assistant
      </p>

      {/* Current plan status */}
      {subscription && (
        <div className={s.statusBar}>
          <div>
            <div className={s.statusLabel}>Current Plan</div>
            <div className={s.statusTier}>
              {subscription.tier_label || subscription.tier}
              {subscription.status === 'trialing' && (
                <span className={s.trialBadge}>Trial</span>
              )}
            </div>
          </div>
          <div>
            <div className={s.tokenUsageLabel}>Token Usage</div>
            <div className={s.tokenUsageValue}>
              {formatTokens(subscription.monthly_tokens_used)} / {formatTokens(subscription.monthly_token_limit)}
            </div>
            <div className={s.progressTrack}>
              <div
                className={s.progressFill}
                style={{
                  width: `${Math.min(100, subscription.monthly_token_limit > 0 ? (subscription.monthly_tokens_used / subscription.monthly_token_limit) * 100 : 0)}%`,
                }}
              />
            </div>
          </div>
          {subscription.stripe_subscription_id && (
            <button onClick={handlePortal} className={s.portalBtn}>
              Manage Billing
            </button>
          )}
        </div>
      )}

      {/* Tier cards */}
      <div className={s.tierGrid}>
        {tiers.map((tier) => (
          <TierCard
            key={tier.key}
            tier={tier}
            isActive={activeTier === tier.key}
            onSelect={handleCheckout}
          />
        ))}
      </div>

      {/* Success/cancel message from Stripe redirect */}
      {(() => {
        const params = new URLSearchParams(window.location.search);
        if (params.get('success') === 'true') {
          return (
            <div className={s.successMsg}>
              Subscription activated successfully! Refresh to see updated plan.
            </div>
          );
        }
        if (params.get('canceled') === 'true') {
          return (
            <div className={s.cancelMsg}>
              Checkout was canceled. You can try again anytime.
            </div>
          );
        }
        return null;
      })()}
    </div>
  );
}
